import{_ as a,c as i,o as p,ag as e}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"完全不懂 也能3 分钟搞懂 Agent Skills，让 AI 自动替你干活","description":"","frontmatter":{"title":"完全不懂 也能3 分钟搞懂 Agent Skills，让 AI 自动替你干活","cover_image":"./Gemini_Generated_Image_u7umbmu7umbmu7um.png"},"headers":[],"relativePath":"ai/2026-02/2026-02-11-skils/index.md","filePath":"ai/2026-02/2026-02-11-skils/index.md","lastUpdated":1774063394000}'),r={name:"ai/2026-02/2026-02-11-skils/index.md"};function o(t,l,s,h,n,k){return p(),i("div",null,l[0]||(l[0]=[e('<p>因为前两天写了关于使用宝玉Skill如何将本地markdown文章推送到推特后台，我看有些人似乎没有使用过Agent Skills，所以写一篇通俗易懂的文章，来简单说一下Agent Skills的强大。</p><p>希望让每个人都能用上更强大的 AI 工具，不做浪潮下的看客，而做驾驭 AI 的人。</p><p>先简单一句话总结：</p><blockquote><p><strong>Agent Skills = 给 AI 安装“技能插件”，让它学会某件事，并且下次还能直接用。</strong></p></blockquote><p>就像手机我们给手机装 App 一样：</p><ul><li><p>想拍照 → 打开相机</p></li><li><p>想聊天 → 打开微信</p></li><li><p>想让 AI 帮你整理笔记 → 用“笔记技能”</p></li><li><p>想让AI帮你下载大片 → 用“下片技能”</p></li><li><p>..........等等等等</p></li></ul><p>这样就不需要每次重新教了！</p><hr><h1 id="一、skills-到底是什么" tabindex="-1">一、Skills 到底是什么？ <a class="header-anchor" href="#一、skills-到底是什么" aria-label="Permalink to &quot;一、Skills 到底是什么？&quot;">​</a></h1><p>先讲解一下以前的情况，AI 能做什么，主要取决于下面的两点：</p><ul><li><p>它学过什么（开始训练数据里包含了哪些知识）</p></li><li><p>你当下告诉它什么（聊天开始或者过程中你喂给它什么数据）</p></li></ul><p>但有个问题：</p><p>👉 <strong>每次我们都需要重新讲一遍，很浪费时间。</strong></p><p>而 Skills 的出现，让 AI 有了长期记忆的工作方法。</p><p>你可以把 AI 想象成：</p><p>🧠 一个超级大脑<br> 🧰 Skills 就是它的工具箱</p><p>工具箱里不只是工具，还有：</p><ul><li><p>使用说明</p></li><li><p>操作步骤</p></li><li><p>注意事项</p></li></ul><p>AI 不需要提前记住所有内容—— 只要需要，就会打开说明书。</p><p>这叫：</p><h1 id="👉-按需学习-只在需要时加载" tabindex="-1">👉 按需学习（只在需要时加载） <a class="header-anchor" href="#👉-按需学习-只在需要时加载" aria-label="Permalink to &quot;👉 按需学习（只在需要时加载）&quot;">​</a></h1><p>非常聪明。</p><hr><h1 id="二、skill-长什么样" tabindex="-1">二、Skill 长什么样？ <a class="header-anchor" href="#二、skill-长什么样" aria-label="Permalink to &quot;二、Skill 长什么样？&quot;">​</a></h1><p>其实，一个 Skill 就像一个文件夹，里面放着：</p><p>![[Pasted image 20260211100414.png]]</p><h3 id="✅-1-操作说明-最重要" tabindex="-1">✅ 1. 操作说明（最重要） <a class="header-anchor" href="#✅-1-操作说明-最重要" aria-label="Permalink to &quot;✅ 1. 操作说明（最重要）&quot;">​</a></h3><p>告诉 AI：</p><ul><li><p>要做什么？</p></li><li><p>按什么步骤？</p></li><li><p>输出什么格式？</p></li></ul><p>例如：</p><blockquote><p>“先读文章 → 判断风格 → 再润色 → 最后输出优化版本”</p></blockquote><hr><h3 id="✅-2-参考资料-可选" tabindex="-1">✅ 2. 参考资料（可选） <a class="header-anchor" href="#✅-2-参考资料-可选" aria-label="Permalink to &quot;✅ 2. 参考资料（可选）&quot;">​</a></h3><p>更详细的说明，比如：</p><ul><li><p>写作技巧</p></li><li><p>编程规则</p></li><li><p>解题思路</p></li></ul><hr><h3 id="✅-3-可执行脚本-进阶" tabindex="-1">✅ 3. 可执行脚本（进阶） <a class="header-anchor" href="#✅-3-可执行脚本-进阶" aria-label="Permalink to &quot;✅ 3. 可执行脚本（进阶）&quot;">​</a></h3><p>比如：</p><ul><li><p>Python 程序、或者可执行的文件</p></li><li><p>自动整理数据的脚本</p></li></ul><p>让 AI 不只是会说，还能会做。</p><hr><h3 id="✅-4-资源文件" tabindex="-1">✅ 4. 资源文件 <a class="header-anchor" href="#✅-4-资源文件" aria-label="Permalink to &quot;✅ 4. 资源文件&quot;">​</a></h3><p>可能包括：</p><ul><li><p>模板</p></li><li><p>图片</p></li><li><p>表格</p></li></ul><hr><h1 id="三、skills-最厉害的地方-省脑子" tabindex="-1">三、Skills 最厉害的地方：省脑子！ <a class="header-anchor" href="#三、skills-最厉害的地方-省脑子" aria-label="Permalink to &quot;三、Skills 最厉害的地方：省脑子！&quot;">​</a></h1><p>如果 AI 一次性记住 50 个技能，会发生什么？</p><p>⚠️ 成本暴涨 （每个技能2000token,50个就是100000token，每次都要发送） ⚠️ 注意力分散 （上下文过长、总要进行压缩） ⚠️ 容易出错</p><p>于是设计者想出了一个非常聪明的机制：</p><h1 id="👉-渐进式加载-progressive-disclosure" tabindex="-1">👉 渐进式加载（Progressive Disclosure） <a class="header-anchor" href="#👉-渐进式加载-progressive-disclosure" aria-label="Permalink to &quot;👉 渐进式加载（Progressive Disclosure）&quot;">​</a></h1><p>听起来复杂，其实非常好理解：</p><h2 id="第一步-只看目录" tabindex="-1">第一步：只看目录 <a class="header-anchor" href="#第一步-只看目录" aria-label="Permalink to &quot;第一步：只看目录&quot;">​</a></h2><p>![[Pasted image 20260211102036.png]]</p><p>图中只是一个Skill的，时间就像一本书的目录。</p><p>AI 只知道：</p><ul><li><p>我会整理 Excel</p></li><li><p>我会写周报</p></li><li><p>我会润色作文</p></li></ul><p>但不知道具体怎么做。</p><p>👉 <strong>占用极少资源，也就一两百的token，多了也就三四百</strong></p><hr><h2 id="第二步-需要时再看说明书" tabindex="-1">第二步：需要时再看说明书 <a class="header-anchor" href="#第二步-需要时再看说明书" aria-label="Permalink to &quot;第二步：需要时再看说明书&quot;">​</a></h2><p>当你说：</p><blockquote><p>“帮我将文章发布到X。”</p></blockquote><p>AI 才会打开“发推文的处理技能”。</p><p>读取详细步骤，也就是去读取SKILL.md， 这样精确到具体的技能说明。</p><p>![[Pasted image 20260211102250.png]]</p><hr><h2 id="第三步-真正干活时再调用工具" tabindex="-1">第三步：真正干活时再调用工具 <a class="header-anchor" href="#第三步-真正干活时再调用工具" aria-label="Permalink to &quot;第三步：真正干活时再调用工具&quot;">​</a></h2><p>比如：</p><ul><li><p>查资料</p></li><li><p>运行脚本</p></li><li><p>读取文件</p></li></ul><p>只有用到才加载，如上面第二步。</p><hr><h1 id="👉-这带来两个巨大好处" tabindex="-1">👉 这带来两个巨大好处： <a class="header-anchor" href="#👉-这带来两个巨大好处" aria-label="Permalink to &quot;👉 这带来两个巨大好处：&quot;">​</a></h1><h3 id="✅-更省资源-更省token-也就是更前" tabindex="-1">✅ 更省资源 更省token(也就是更前) <a class="header-anchor" href="#✅-更省资源-更省token-也就是更前" aria-label="Permalink to &quot;✅ 更省资源 更省token(也就是更前)&quot;">​</a></h3><h3 id="✅-更专注-不容易出错-上下文短理解就更好一些" tabindex="-1">✅ 更专注，不容易出错（上下文短理解就更好一些） <a class="header-anchor" href="#✅-更专注-不容易出错-上下文短理解就更好一些" aria-label="Permalink to &quot;✅ 更专注，不容易出错（上下文短理解就更好一些）&quot;">​</a></h3><p>这就是为什么很多专家认为：</p><blockquote><p><strong>Skills 是未来 AI 工作方式的重要方向。</strong></p></blockquote><hr><h2 id="skills-像工作流程打包器" tabindex="-1">Skills 像工作流程打包器 <a class="header-anchor" href="#skills-像工作流程打包器" aria-label="Permalink to &quot;Skills 像工作流程打包器&quot;">​</a></h2><p>适合：</p><ul><li><p>固定学习方法</p></li><li><p>写作流程</p></li><li><p>编程步骤</p></li><li><p>知识整理</p></li></ul><p>👉 更偏向本地能力，也可以写脚本调用外部接口，Skills中也可以调用MCP（这里不过多强调知道有这么个词就好）。</p><hr><h1 id="👉-未来很可能是这样的组合" tabindex="-1">👉 未来很可能是这样的组合： <a class="header-anchor" href="#👉-未来很可能是这样的组合" aria-label="Permalink to &quot;👉 未来很可能是这样的组合：&quot;">​</a></h1><ul><li><p>AI 自带基础能力</p></li><li><p>MCP 负责连接世界</p></li><li><p>Skills 帮你形成自己的学习和工作体系</p></li></ul><p>三者并不会互相取代，而是协作。</p><hr><h1 id="五、我们为什么更应该早点了解-skills" tabindex="-1">五、我们为什么更应该早点了解 Skills？ <a class="header-anchor" href="#五、我们为什么更应该早点了解-skills" aria-label="Permalink to &quot;五、我们为什么更应该早点了解 Skills？&quot;">​</a></h1><p>因为未来学习方式正在改变。</p><p>不再只是：</p><blockquote><p>背知识的人更强</p></blockquote><p>而是：</p><blockquote><p><strong>会使用 AI 系统的人更强。</strong></p></blockquote><p>举个例子：</p><p>普通自媒体工作者：</p><blockquote><p>每次写作文 → 从零开始。</p></blockquote><p>会用 Skills 的AI自媒体：</p><ul><li><p>自动整理素材</p></li><li><p>优化结构</p></li><li><p>检查逻辑</p></li><li><p>提供高级表达</p></li></ul><p>效率可能高出 <strong>30%–70%</strong>。差距会越来越明显。</p><hr><h1 id="六、哪里可以找到-skills" tabindex="-1">六、哪里可以找到 Skills？ <a class="header-anchor" href="#六、哪里可以找到-skills" aria-label="Permalink to &quot;六、哪里可以找到 Skills？&quot;">​</a></h1><p>现在已经有很多开源社区，例如： <a href="https://skills.sh" target="_blank" rel="noreferrer">https://skills.sh</a></p><p>而且好消息是：</p><h1 id="👉-写-skill-的门槛非常低" tabindex="-1">👉 写 Skill 的门槛非常低！ <a class="header-anchor" href="#👉-写-skill-的门槛非常低" aria-label="Permalink to &quot;👉 写 Skill 的门槛非常低！&quot;">​</a></h1><p>只要你会写清楚步骤，就能做一个。</p><p>甚至已经有工具：</p><blockquote><p>用自然语言描述需求 → 自动生成 Skill。</p></blockquote><p>未来可能人人都会拥有：</p><hr><h1 id="⭐-最后总结" tabindex="-1">⭐ 最后总结 <a class="header-anchor" href="#⭐-最后总结" aria-label="Permalink to &quot;⭐ 最后总结&quot;">​</a></h1><blockquote><p><strong>努力只是线性增长的话，那么能驾驭AI系统是人便会呈现指数级的增长。</strong></p></blockquote><p>早点理解 Skills，不是为了炫技，而是为了在未来的学习竞争中——</p><p>👉 <strong>拥有真正的“超能力”。</strong></p>',112)]))}const c=a(r,[["render",o]]);export{d as __pageData,c as default};
